import{k as e,p as t,u as n}from"./chunks/runtime-core.esm-bundler.PK8HO-US.js";import{t as r}from"./chunks/plugin-vue_export-helper.DrfHhw6c.js";import{n as i,r as a,t as o}from"./chunks/extension-view.BUCve89_.js";const s=JSON.parse(`{"title":"Налаштування VS Code","description":"Покрокова інструкція з налаштування Visual Studio Code для створення модів Fabric.","frontmatter":{"title":"Налаштування VS Code","description":"Покрокова інструкція з налаштування Visual Studio Code для створення модів Fabric.","authors":["dicedpixels"],"prev":{"text":"Налаштування вашого IDE","link":"../setting-up"},"next":{"text":"Відкриття проєкту у VS Code","link":"./opening-a-project"},"resources":{"https://code.visualstudio.com/":"Завантажити Visual Studio Code","https://marketplace.visualstudio.com/items?itemName=vscjava.vscode-java-pack":"Пакет розширень для Java — VS Marketplace"},"files":[]},"headers":[],"relativePath":"uk_ua/develop/getting-started/vscode/setting-up.md","filePath":"translated/uk_ua/develop/getting-started/vscode/setting-up.md","lastUpdated":1774518827000}`);var c={name:`uk_ua/develop/getting-started/vscode/setting-up.md`};function l(r,i,a,o,s,c){return e(),n(`div`,null,[...i[0]||=[t(`<h1 id="h1" tabindex="-1">Налаштування VS Code <a class="header-anchor" href="#h1" aria-label="Permalink to “Налаштування VS Code”">​</a></h1><div class="warning custom-block"><p class="custom-block-title">ВАЖЛИВО</p><p>Хоча можна розробляти моди за допомогою Visual Studio Code, ми рекомендуємо цього не робити. Розгляньте можливість використання <a href="./../intellij-idea/setting-up">IntelliJ IDEA</a>, який містить спеціальні інструменти Java, розширені функції та корисні плаґіни, створені спільнотою, такі як <strong>Minecraft Development</strong>.</p></div><div class="info custom-block"><p class="custom-block-title">ПЕРЕДУМОВИ</p><p>Спершу переконайтеся, що ви <a href="./../setting-up#install-jdk-21">встановили JDK</a>.</p></div><h2 id="installation" tabindex="-1">Установлення <a class="header-anchor" href="#installation" aria-label="Permalink to “Установлення”">​</a></h2><p>Ви можете завантажити Visual Studio Code з <a href="https://code.visualstudio.com/" target="_blank" rel="noreferrer">code.visualstudio.com</a> або через бажаний менеджер пакетів.</p><p><img src="/assets/develop/getting-started/vscode/download.png" alt="Сторінка завантаження Visual Studio Code" loading="lazy"></p><h2 id="prerequisites" tabindex="-1">Передумови <a class="header-anchor" href="#prerequisites" aria-label="Permalink to “Передумови”">​</a></h2><p>Visual Studio Code не підтримує мову Java із коробки. Однак Microsoft надає зручний пакет розширень, який містить усі необхідні розширення для її підтримки.</p><p>Ви можете встановити цей пакет розширення з <a href="https://marketplace.visualstudio.com/items?itemName=vscjava.vscode-java-pack" target="_blank" rel="noreferrer">Visual Studio Marketplace</a>.</p><p><img src="/assets/develop/getting-started/vscode/extension.png" alt="Пакет розширення Java" loading="lazy"></p><p>Або, у самому Visual Studio Code, через подання розширень.</p><p><img src="/assets/develop/getting-started/vscode/extension-view.png" alt="Пакет розширень для Java у режимі подання розширень" loading="lazy"></p><p>Розширення <strong>Language Support for Java</strong> запропонує вам екран запуску для налаштування JDK. Ви можете це зробити, якщо ви ще цього не зробили.</p>`,13)]])}var u=r(c,[[`render`,l]]);export{s as __pageData,u as default};